func getSlope(point1: Array<Int64>, point2: Array<Int64>) -> Int64 {
    let dx = point2[0] - point1[0]
    let dy = point2[1] - point1[1]
    if dx == 0 && dy == 0 {
        return 0
    }
    if dx == 0 {
        return 1 // vertical line
    }
    return dy * 1000000000 / dx
